import{_ as l,o as a,c as e,a2 as i}from"./chunks/framework.VxKNwi4m.js";const f=JSON.parse('{"title":"권리 의무 승계","description":"","frontmatter":{},"headers":[],"relativePath":"contract/succession.md","filePath":"contract/succession.md","lastUpdated":1781979631000}'),r={name:"contract/succession.md"};function o(n,t,s,d,h,c){return a(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="권리-의무-승계" tabindex="-1">권리 의무 승계 <a class="header-anchor" href="#권리-의무-승계" aria-label="Permalink to &quot;권리 의무 승계&quot;">​</a></h1><p>계약의 권리 및 의무를 양도/양수하는 승계 정보를 관리하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>계약 정보 관리 &gt; 권리 의무 승계</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>특정 계약에 대한 권리 의무 승계 내역을 조회하고, 새로운 승계 건을 등록하거나 기존 승계 정보를 수정할 수 있습니다. 양도 계약자 및 양수 계약자의 정보를 입력하고, 승계 관련 일자 및 변경 인가 여부를 관리합니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li>계약자 검색 및 선택 기능 (양도 계약자 지정)</li><li>승계 진행 건 목록 조회 및 엑셀 출력</li><li>새로운 권리 의무 승계 등록</li><li>기존 권리 의무 승계 정보 수정 및 삭제</li><li>양도 계약자 및 양수 계약자 정보 관리</li><li>승계 신청일, 매매 계약일, 변경 인가일 등 주요 일자 관리</li><li>변경 인가 여부 설정</li><li>URL 파라미터를 통한 특정 승계 건 하이라이트 및 페이지 이동 지원</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-계약자-검색-및-선택" tabindex="-1">1. 계약자 검색 및 선택 <a class="header-anchor" href="#_1-계약자-검색-및-선택" aria-label="Permalink to &quot;1. 계약자 검색 및 선택&quot;">​</a></h3><p>양도 계약자를 검색하고 선택할 수 있는 기능을 제공합니다. 검색 결과는 버튼 형태로 표시되어 쉽게 선택할 수 있습니다.</p><h4 id="주요-기능-1" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능-1" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h4><ul><li><strong>검색 입력 필드</strong>: 계약자명, 비고, 계약 일련번호로 검색</li><li><strong>검색 버튼</strong>: 검색 실행</li><li><strong>검색 결과 목록</strong>: 검색된 계약자 목록을 버튼 형태로 표시, 클릭 시 해당 계약자를 양도 계약자로 설정하고 상세 정보 로드</li></ul><h3 id="_2-계약-관리-내비게이션" tabindex="-1">2. 계약 관리 내비게이션 <a class="header-anchor" href="#_2-계약-관리-내비게이션" aria-label="Permalink to &quot;2. 계약 관리 내비게이션&quot;">​</a></h3><p>계약 상세 관리, 권리 의무 승계, 계약 해지 관리 페이지로 이동할 수 있는 탭 형태의 내비게이션을 제공합니다. 현재 활성화된 페이지를 시각적으로 표시합니다.</p><h4 id="주요-항목" tabindex="-1">주요 항목 <a class="header-anchor" href="#주요-항목" aria-label="Permalink to &quot;주요 항목&quot;">​</a></h4><ul><li>계약 상세 관리 버튼</li><li>권리 의무 승계 버튼</li><li>계약 해지 관리 버튼</li></ul><h3 id="_3-계약자-정보-알림" tabindex="-1">3. 계약자 정보 알림 <a class="header-anchor" href="#_3-계약자-정보-알림" aria-label="Permalink to &quot;3. 계약자 정보 알림&quot;">​</a></h3><p>현재 선택된 양도 계약자의 주요 정보(계약자명, 현재 상태)를 알림 형태로 표시합니다. 계약자 선택 해제 기능과 함께, 승계 진행 중이거나 해지된 계약자에 대한 특별 알림을 제공합니다.</p><h4 id="주요-표시-항목" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><ul><li>계약자명</li><li>현재 상태 (청약, 계약, 해지신청, 해지완료 등)</li><li>승계 진행 중 여부</li><li>계약자 선택 해제 버튼</li></ul><h3 id="_4-승계-등록-수정-버튼" tabindex="-1">4. 승계 등록/수정 버튼 <a class="header-anchor" href="#_4-승계-등록-수정-버튼" aria-label="Permalink to &quot;4. 승계 등록/수정 버튼&quot;">​</a></h3><p>새로운 승계 건을 등록하거나, 현재 조회 중인 승계 건을 수정하기 위한 버튼을 제공합니다. 승계 진행 상태에 따라 버튼의 텍스트와 색상이 변경됩니다.</p><h4 id="주요-기능-2" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능-2" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h4><ul><li>&#39;등록하기&#39; 또는 &#39;수정하기&#39; 버튼 클릭 시 권리 의무 승계 등록/수정 폼 모달 호출.</li></ul><h3 id="_5-승계-진행-건-목록" tabindex="-1">5. 승계 진행 건 목록 <a class="header-anchor" href="#_5-승계-진행-건-목록" aria-label="Permalink to &quot;5. 승계 진행 건 목록&quot;">​</a></h3><p>등록된 권리 의무 승계 건들의 목록을 테이블 형태로 표시합니다. 각 승계 건에 대한 상세 정보와 확인 버튼을 제공합니다.</p><h4 id="주요-표시-항목-1" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목-1" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">항목</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;">계약 정보</td><td style="text-align:left;">승계 대상 계약의 일련번호</td></tr><tr><td style="text-align:left;">양도계약자</td><td style="text-align:left;">권리를 양도하는 계약자의 이름</td></tr><tr><td style="text-align:left;">양수계약자</td><td style="text-align:left;">권리를 양수받는 계약자의 이름</td></tr><tr><td style="text-align:left;">승계신청일</td><td style="text-align:left;">승계 신청이 접수된 날짜</td></tr><tr><td style="text-align:left;">매매계약일</td><td style="text-align:left;">양도/양수 계약이 체결된 날짜</td></tr><tr><td style="text-align:left;">변경인가일</td><td style="text-align:left;">승계에 대한 변경 인가가 완료된 날짜</td></tr><tr><td style="text-align:left;">변경인가여부</td><td style="text-align:left;">승계에 대한 변경 인가 완료 여부</td></tr><tr><td style="text-align:left;">확인</td><td style="text-align:left;">승계 상세 정보를 확인하거나 수정하는 버튼</td></tr></tbody></table><h3 id="_6-권리-의무-승계-등록-수정-폼" tabindex="-1">6. 권리 의무 승계 등록/수정 폼 <a class="header-anchor" href="#_6-권리-의무-승계-등록-수정-폼" aria-label="Permalink to &quot;6. 권리 의무 승계 등록/수정 폼&quot;">​</a></h3><p>새로운 권리 의무 승계 정보를 등록하거나 기존 정보를 수정하는 모달 폼입니다. 양도 계약자 정보는 자동으로 채워지며, 양수 계약자의 상세 정보를 입력합니다.</p><h4 id="주요-입력-항목" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><ul><li><strong>양도계약자</strong>: (자동 입력) 권리를 양도하는 계약자 정보.</li><li><strong>승계신청일</strong>: 필수. 승계 신청이 접수된 날짜.</li><li><strong>매매계약일</strong>: 필수. 양도/양수 계약이 체결된 날짜.</li><li><strong>양수계약자 인적사항</strong>: <ul><li>이름: 필수. 양수 계약자의 성명.</li><li>생년월일: 필수. 양수 계약자의 생년월일.</li><li>성별: 필수. 양수 계약자의 성별.</li><li>휴대전화: 필수. 양수 계약자의 휴대전화 번호.</li><li>집전화, 기타연락처, 이메일: 양수 계약자의 추가 연락처 정보.</li><li>주민등록주소: 필수. 양수 계약자의 주민등록 주소 (우편번호 API 연동).</li><li>우편송달주소: 필수. 양수 계약자의 우편물 수령 주소 (주민등록 주소와 동일 설정 가능, 우편번호 API 연동).</li></ul></li><li><strong>변경인가여부</strong>: 변경 인가 완료 여부 체크박스.</li><li><strong>변경인가일</strong>: 변경 인가 완료 시 날짜 입력.</li><li><strong>비고</strong>: 기타 특이사항.</li></ul>',32)])])}const g=l(r,[["render",o]]);export{f as __pageData,g as default};
